19→export function parseRich(raw: string): { text: string; style?: React.CSSProperties } {
20→    try {
21→        if (raw && raw.startsWith('{"__rich"')) {
22→            const parsed: RichValue = JSON.parse(raw);
23→            const style: React.CSSProperties = {};
24→            if (parsed.gradient) {
25→                const dir = parsed.gradient.direction ?? 'to right';
26→                style.backgroundImage = `linear-gradient(${dir}, ${parsed.gradient.from}, ${parsed.gradient.to})`;
27→                style.WebkitBackgroundClip = 'text';
28→                style.WebkitTextFillColor = 'transparent';
29→                style.backgroundClip = 'text';
30→                style.display = 'inline-block';
31→            } else if (parsed.color) {
32→                style.color = parsed.color;
33→            }
34→            return { text: parsed.text, style };
35→        }
36→    } catch { /* not rich */ }
37→    return { text: raw };
38→}
