22→/**
23→ * Transforms a standard video or document URL into an embeddable format.
24→ * Handles:
25→ * - YouTube (watch?v=... -> embed/...)
26→ * - Vimeo (vimeo.com/... -> player.vimeo.com/video/...)
27→ * - Google Drive (file/d/.../view -> file/d/.../preview)
28→ */
29→export const getEmbedUrl = (url: string | null | undefined): string => {
30→    if (!url) return '';
31→
32→    try {
33→        // YouTube handling
34→        if (url.includes('youtube.com/watch')) {
35→            const videoId = new URL(url).searchParams.get('v');
36→            if (videoId) return `https://www.youtube.com/embed/${videoId}?modestbranding=1`;
37→        }
38→        if (url.includes('youtu.be/')) {
39→            const videoId = url.split('youtu.be/')[1].split('?')[0];
40→            if (videoId) return `https://www.youtube.com/embed/${videoId}?modestbranding=1`;
41→        }
42→
43→        // Vimeo handling
44→        if (url.includes('vimeo.com/') && !url.includes('player.vimeo.com')) {
45→            const videoId = url.split('vimeo.com/')[1].split('?')[0];
46→            if (videoId && !isNaN(Number(videoId))) {
47→                return `https://player.vimeo.com/video/${videoId}`;
48→            }
49→        }
50→
51→        // Google Drive handling
52→        if (url.includes('drive.google.com/file/d/')) {
53→            if (url.endsWith('/view') || url.includes('/view?')) {
54→                return url.replace('/view', '/preview');
55→            }
56→            if (!url.includes('/preview')) {
57→                // Ensure it ends with /preview if it's a file link
58→                const base = url.split('?')[0];
59→                return `${base}/preview`;
60→            }
61→        }
62→
63→        return url;
64→    } catch (e) {
65→        return url;
66→    }
67→};
