73→export const isEmbeddable = (url: string | null | undefined): boolean => {
74→    if (!url) return false;
75→
76→    // Explicitly non-embeddable common domains
77→    const nonEmbeddable = [
78→        'google.com',
79→        'facebook.com',
80→        'instagram.com',
81→        'twitter.com',
82→        'linkedin.com'
83→    ];
84→
85→    try {
86→        const hostname = new URL(url).hostname.replace('www.', '');
87→
88→        // If it's a Google Drive preview/embed link, it is embeddable
89→        if (url.includes('drive.google.com') && (url.includes('/preview') || url.includes('/embed'))) {
90→            return true;
91→        }
92→
93→        // If it's a YouTube embed link, it is embeddable
94→        if (url.includes('youtube.com/embed') || url.includes('player.vimeo.com')) {
